import React, { useContext } from "react";
import { CartContext } from "../context/CartContext";

function CheckoutPanel() {
  const {
    cartItems,
    updateQuantity,
    removeFromCart,
    checkoutOpen,
    toggleCheckout,
  } = useContext(CartContext);

  if (!checkoutOpen) return null;

  const total = cartItems.reduce(
    (acc, item) => acc + item.price * item.quantity,
    0
  );

  return (
    <>
      {/* Overlay */}
      <div
        onClick={toggleCheckout}
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          width: "100vw",
          height: "100vh",
          background: "rgba(0,0,0,0.5)",
          zIndex: 999,
        }}
      />

      {/* Slide-out Panel */}
      <div
        style={{
          position: "fixed",
          top: 0,
          right: 0,
          width: "380px",
          height: "100vh",
          background: "#fff",
          boxShadow: "-2px 0 10px rgba(0,0,0,0.2)",
          padding: "20px",
          overflowY: "auto",
          zIndex: 1000,
          transform: checkoutOpen ? "translateX(0)" : "translateX(100%)",
          transition: "transform 0.3s ease-in-out",
          display: "flex",
          flexDirection: "column",
        }}
      >
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <h2>Your Cart</h2>
          <button
            onClick={toggleCheckout}
            style={{
              background: "transparent",
              border: "none",
              fontSize: "20px",
              cursor: "pointer",
            }}
          >
            ✖
          </button>
        </div>

        {/* Cart Items */}
        <div style={{ flex: 1, marginTop: "10px" }}>
          {cartItems.length === 0 ? (
            <p style={{ textAlign: "center" }}>🛒 Cart is empty</p>
          ) : (
            cartItems.map((item) => (
              <div
                key={item.id || item._id}
                style={{
                  marginBottom: "15px",
                  borderBottom: "1px solid #eee",
                  paddingBottom: "10px",
                }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                  <img
                    src={item.image}
                    alt={item.name}
                    style={{ width: "60px", height: "60px", objectFit: "cover" }}
                  />
                  <div style={{ flex: 1 }}>
                    <h4 style={{ margin: "0 0 5px" }}>{item.name}</h4>
                    <p style={{ margin: 0 }}>₹{item.price}</p>
                    <div style={{ display: "flex", alignItems: "center", marginTop: "5px" }}>
                      <button
                        onClick={() => updateQuantity(item.id, item.quantity - 1)}
                        style={{
                          padding: "3px 8px",
                          background: "#ddd",
                          border: "none",
                          cursor: "pointer",
                        }}
                      >
                        -
                      </button>
                      <span style={{ margin: "0 10px" }}>{item.quantity}</span>
                      <button
                        onClick={() => updateQuantity(item.id, item.quantity + 1)}
                        style={{
                          padding: "3px 8px",
                          background: "#ddd",
                          border: "none",
                          cursor: "pointer",
                        }}
                      >
                        +
                      </button>
                    </div>
                    <button
                      onClick={() => removeFromCart(item.id)}
                      style={{
                        background: "none",
                        border: "none",
                        color: "red",
                        marginTop: "5px",
                        cursor: "pointer",
                      }}
                    >
                      Remove
                    </button>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Checkout Summary */}
        {cartItems.length > 0 && (
          <div
            style={{
              borderTop: "1px solid #ddd",
              paddingTop: "15px",
              marginTop: "auto",
            }}
          >
            <h3>Total: ₹{total.toFixed(2)}</h3>
            <form
              onSubmit={(e) => {
                e.preventDefault();
                alert("✅ Order placed successfully!");
                toggleCheckout();
              }}
            >
              <input
                type="text"
                placeholder="Name"
                required
                style={{
                  width: "100%",
                  marginBottom: "10px",
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "4px",
                }}
              />
              <input
                type="text"
                placeholder="Address"
                required
                style={{
                  width: "100%",
                  marginBottom: "10px",
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "4px",
                }}
              />
              <input
                type="text"
                placeholder="Payment Method"
                required
                style={{
                  width: "100%",
                  marginBottom: "10px",
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "4px",
                }}
              />
              <button
                type="submit"
                style={{
                  width: "100%",
                  background: "#28a745",
                  color: "#fff",
                  padding: "10px",
                  border: "none",
                  borderRadius: "4px",
                  cursor: "pointer",
                  fontWeight: "bold",
                }}
              >
                Place Order
              </button>
            </form>
          </div>
        )}
      </div>
    </>
  );
}

export default CheckoutPanel;
